/**
 * MMS Worker Daemon Runner
 *
 * Entry point for starting all background workers.
 * Handles graceful shutdown and health monitoring.
 *
 * Usage:
 *   bun run src/workers/runner.ts
 *   or
 *   WORKERS=optimizer,drift_monitor bun run src/workers/runner.ts
 *
 * Environment Variables:
 *   WORKERS - Comma-separated list of workers to start (default: all)
 *   REDIS_HOST - Redis server host (default: localhost)
 *   REDIS_PORT - Redis server port (default: 6379)
 *   REDIS_PASSWORD - Redis password (optional)
 *
 * @see specs/002-architecture.md Section 2.4 - Worker Layer
 * @see specs/004-domain-services.md Section 4.8
 */

import { logger } from '../lib/logging/logger';
import {
  registerWorker,
  closeAllWorkers,
  getWorkersHealth,
  QUEUE_NAMES,
  type WorkerJobContext,
} from './index';

// Import all worker processors
import { processOptimizerJob } from './processors/optimizer';
import { processDriftMonitorJob } from './processors/drift-monitor';
import { processIngestionJob } from './processors/ingestion';
import { processMaximoSyncJob } from './processors/maximo-sync';
import { processStrategicPlannerJob } from './processors/strategic-planner';
import { processNotificationJob } from './processors/notification';
import { processTacticalSchedulerJob } from './processors/tactical-scheduler';
import { processManhourLevelingJob } from './processors/manhour-leveling';
import { processReportJob } from './processors/report';


// =============================================================================
// Worker Registry
// =============================================================================

const log = logger.child({ module: 'worker-runner' });

/**
 * Available worker processors
 */
const WORKER_PROCESSORS: Record<
  keyof typeof QUEUE_NAMES,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  ((context: WorkerJobContext<any>) => Promise<unknown>) | null
> = {
  INGESTION: processIngestionJob,
  TACTICAL_SCHEDULER: processTacticalSchedulerJob,
  STRATEGIC_PLANNER: processStrategicPlannerJob,
  OPTIMIZER: processOptimizerJob,
  MANHOUR_LEVELING: processManhourLevelingJob,
  DRIFT_MONITOR: processDriftMonitorJob,
  NOTIFICATION: processNotificationJob,
  REPORT: processReportJob,
  MAXIMO_SYNC: processMaximoSyncJob,
};

// =============================================================================
// Worker Startup
// =============================================================================

/**
 * Start specified workers or all available workers
 *
 * @param workerKeys - Optional list of worker keys to start
 */
export async function startWorkers(
  workerKeys?: Array<keyof typeof QUEUE_NAMES>
): Promise<void> {
  const keys = workerKeys ?? (Object.keys(WORKER_PROCESSORS) as Array<keyof typeof QUEUE_NAMES>);

